        decRight2[i] = 1;
        if (nums[i] < nums[i - 1]) {
            decRight2[i] = decRight2[i - 1] + 1;
        }
    }

    // Check all possible triplets (l, p, q, r)
    for (int l = 0; l < n - 3; l++) {
        for (int p = l + 1; p < n - 2; p++) {
            for (int q = p + 1; q < n - 1; q++) {
                for (int r = q + 1; r < n; r++) {
                    // Check if the three parts are strictly increasing, decreasing, increasing
                    if (nums[p] > nums[p - 1] && nums[q] < nums[q - 1] && nums[q] < nums[q + 1]) {
                        // Calculate the sum of the triplet
                        long sum = 0;
                        for (int i = l; i <= r; i++) {
                            sum += nums[i];
                        }
                        maxSum = Math.max(maxSum, sum);
                    }
                }
            }
        }
    }

    return maxSum;
}
